fn calendar_days_to_class_vec(ticks: &[tick::CalendarDay]) -> Vec<CalendarDay> {
    ticks
        .iter()
        .map(|t| {
            CalendarDay {
                date: t.date,
                is_open: t.is_open,
                open_time: t.open_time,
                close_time: t.close_time,
                status: t.status.as_str().to_string(),
            }
        })
        .collect()
}

fn eod_ticks_to_class_vec(ticks: &[tick::EodTick]) -> Vec<EodTick> {
    ticks
        .iter()
        .map(|t| {
            EodTick {
                created_ms_of_day: t.created_ms_of_day,
                last_trade_ms_of_day: t.last_trade_ms_of_day,
                open: t.open,
                high: t.high,
                low: t.low,
                close: t.close,
                volume: BigInt::from(t.volume),
                count: BigInt::from(t.count),
                bid_size: t.bid_size,
                bid_exchange: t.bid_exchange,
                bid: t.bid,
                bid_condition: t.bid_condition,
                ask_size: t.ask_size,
                ask_exchange: t.ask_exchange,
                ask: t.ask,
                ask_condition: t.ask_condition,
                date: t.date,
                expiration: t.has_contract_id().then_some(t.expiration),
                strike: t.has_contract_id().then_some(t.strike),
                right: if t.right == '\0' { None } else { Some(t.right.to_string()) },
            }
        })
        .collect()
}

